"use strict";let tasks=loadTasks(),currentFilter="all",currentSort="created-desc";const form=document.getElementById("task-form"),input=document.getElementById("task-input"),list=document.getElementById("task-list"),emptyState=document.getElementById("empty-state"),countLabel=document.getElementById("task-count"),clearDoneBtn=document.getElementById("clear-done"),filterButtons=document.querySelectorAll(".filters__btn"),sortSelect=document.getElementById("sort-select");function loadTasks(){const e=localStorage.getItem("tasks");if(!e)return[];try{return JSON.parse(e)}catch(e){return[]}}function saveTasks(){localStorage.setItem("tasks",JSON.stringify(tasks))}function sanitize(e){return window.DOMPurify?DOMPurify.sanitize(e,{ALLOWED_TAGS:[]}):e.replace(/</g,"&lt;").replace(/>/g,"&gt;")}function addTask(e){const t=sanitize(e.trim());""!==t&&(tasks.push({id:Date.now().toString(),text:t,done:!1,createdAt:Date.now()}),saveTasks(),render())}function toggleTask(e){for(const t of tasks)t.id===e&&(t.done=!t.done);saveTasks(),render()}function deleteTask(e){tasks=tasks.filter(t=>t.id!==e),saveTasks(),render()}function clearDone(){tasks=tasks.filter(e=>!e.done),saveTasks(),render()}function getVisibleTasks(){let e=tasks;return"active"===currentFilter?e=e.filter(e=>!e.done):"done"===currentFilter&&(e=e.filter(e=>e.done)),e=e.slice(),"created-asc"===currentSort?e.sort((e,t)=>e.createdAt-t.createdAt):"alpha-asc"===currentSort?e.sort((e,t)=>e.text.localeCompare(t.text,"ru")):"status"===currentSort?e.sort((e,t)=>e.done-t.done):e.sort((e,t)=>t.createdAt-e.createdAt),e}function render(){const e=getVisibleTasks();list.innerHTML="",e.forEach(e=>{const t=document.createElement("li");t.className="task"+(e.done?" is-done":"");const n=document.createElement("input");n.type="checkbox",n.className="task__check",n.checked=e.done,n.addEventListener("change",()=>toggleTask(e.id));const s=document.createElement("span");s.className="task__text",s.textContent=e.text;const a=document.createElement("button");a.type="button",a.className="task__delete",a.textContent="✕",a.addEventListener("click",()=>deleteTask(e.id)),t.appendChild(n),t.appendChild(s),t.appendChild(a),list.appendChild(t)}),emptyState.hidden=0!==e.length;const t=tasks.filter(e=>!e.done).length;countLabel.textContent=t+" задач"}form.addEventListener("submit",function(e){e.preventDefault(),addTask(input.value),input.value=""}),filterButtons.forEach(e=>{e.addEventListener("click",()=>{filterButtons.forEach(e=>e.classList.remove("is-active")),e.classList.add("is-active"),currentFilter=e.dataset.filter,render()})}),sortSelect.addEventListener("change",()=>{currentSort=sortSelect.value,render()}),clearDoneBtn.addEventListener("click",clearDone),render();